﻿@inherits LayoutComponentBase

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Progress is { CurrentStep: > 0 })
            {
                <div class="wizard-progress d-flex align-items-center gap-2 me-auto">
                    @for (int i = 1; i <= Progress.TotalSteps; i++)
                    {
                        var step = i;
                        var label = step switch
                        {
                            1 => "Personal Info",
                            2 => "Experience",
                            3 => "References",
                            4 => "Review",
                            _ => $"Step {step}"
                        };
                        var href = step switch
                        {
                            1 => "apply/personal-info",
                            2 => "apply/experience",
                            3 => "apply/references",
                            4 => "apply/review",
                            _ => "#"
                        };
                        var isActive = step == Progress.CurrentStep;
                        var isCompleted = Progress.CompletedSteps[step - 1];
                        <a href="@href"
                           class="badge @(isActive ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary")">
                            @step. @label
                        </a>
                    }
                    <span class="ms-2 text-muted small">
                        Step @Progress.CurrentStep of @Progress.TotalSteps
                    </span>
                </div>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

