@page "/apply/personal-info"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input type="email" class="form-control" @bind="AppState.Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    protected override async Task OnInitializedAsync()
    {
        var progress = new WizardProgress(1, 4, GetCompletedSteps());
        await ProgressSource.NotifyChangedAsync(progress);
    }

    private async Task Next()
    {
        var completed = GetCompletedSteps();
        completed[0] = true;
        await ProgressSource.NotifyChangedAsync(new WizardProgress(2, 4, completed));
        Nav.NavigateTo("apply/experience");
    }

    private bool[] GetCompletedSteps()
    {
        return
        [
            !string.IsNullOrWhiteSpace(AppState.Name) && !string.IsNullOrWhiteSpace(AppState.Email),
            AppState.Jobs.Count > 0,
            AppState.References.Count > 0,
            false
        ];
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Experience</h1>

@for (int i = 0; i < AppState.Jobs.Count; i++)
{
    var index = i;
    var job = AppState.Jobs[index];
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Job @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => AppState.Jobs.RemoveAt(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="job.Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(2, 4, GetCompletedSteps()));
    }

    private void AddJob() => AppState.Jobs.Add(new JobEntry());

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(1, 4, GetCompletedSteps()));
        Nav.NavigateTo("apply/personal-info");
    }

    private async Task Next()
    {
        var completed = GetCompletedSteps();
        completed[1] = true;
        await ProgressSource.NotifyChangedAsync(new WizardProgress(3, 4, completed));
        Nav.NavigateTo("apply/references");
    }

    private bool[] GetCompletedSteps()
    {
        return
        [
            !string.IsNullOrWhiteSpace(AppState.Name) && !string.IsNullOrWhiteSpace(AppState.Email),
            AppState.Jobs.Count > 0,
            AppState.References.Count > 0,
            false
        ];
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – References</PageTitle>

<h1>Step 3: References</h1>

@for (int i = 0; i < AppState.References.Count; i++)
