            AppState.References.Count > 0,
            false
        ];
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<h4>Personal Information</h4>
<dl class="row">
    <dt class="col-sm-3">Name</dt>
    <dd class="col-sm-9">@AppState.Name</dd>
    <dt class="col-sm-3">Email</dt>
    <dd class="col-sm-9">@AppState.Email</dd>
</dl>

<h4>Experience</h4>
@if (AppState.Jobs.Count == 0)
{
    <p class="text-muted">No jobs added.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th></tr>
        </thead>
        <tbody>
            @foreach (var job in AppState.Jobs)
            {
                <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
            }
        </tbody>
    </table>
}

<h4>References</h4>
@if (AppState.References.Count == 0)
{
    <p class="text-muted">No references added.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Name</th><th>Email</th><th>Relationship</th></tr>
        </thead>
        <tbody>
            @foreach (var r in AppState.References)
            {
                <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
            }
        </tbody>
    </table>
}

<div class="d-flex gap-2 mt-3">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(4, 4, GetCompletedSteps()));
    }

    private async Task Back()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress(3, 4, GetCompletedSteps()));
        Nav.NavigateTo("apply/references");
    }

    private async Task Submit()
    {
        var completed = GetCompletedSteps();
        completed[3] = true;
        await ProgressSource.NotifyChangedAsync(new WizardProgress(4, 4, completed));
        submitted = true;
    }

    private bool[] GetCompletedSteps()
    {
        return
        [
            !string.IsNullOrWhiteSpace(AppState.Name) && !string.IsNullOrWhiteSpace(AppState.Email),
            AppState.Jobs.Count > 0,
            AppState.References.Count > 0,
            false
        ];
    }
}

